{
  "$schema": "https://raw.githubusercontent.com/JanDeDobbeleer/oh-my-posh/main/themes/schema.json",
  "blocks": [
    {
      "type": "prompt",
      "alignment": "left",
      "segments": [
        {
          "properties": {
            "cache_duration": "none",
            "macos": "\uf179 ",
            "ubuntu": "\uf31b ",
            "windows": "\ue70f "
          },
          "leading_diamond": "\u256d\u2500\ue0b2",
          "template": " {{ .Icon }} ",
          "foreground": "#011627",
          "background": "#FEF5ED",
          "type": "os",
          "style": "diamond"
        },
        {
          "properties": {
            "cache_duration": "none"
          },
          "template": " \ue266 MEM:{{ round .PhysicalPercentUsed .Precision }}% [{{ (div ((sub .PhysicalTotalMemory .PhysicalAvailableMemory)|float64) 1073741824.0) }}/{{ (div .PhysicalTotalMemory 1073741824.0) }}GB] ",
          "foreground": "#FFFFFF",
          "powerline_symbol": "\ue0b0",
          "background": "#516BEB",
          "type": "sysinfo",
          "style": "powerline"
        },
        {
          "properties": {
            "cache_duration": "none"
          },
          "template": " \uf073 {{ .CurrentDate | date .Format }} ",
          "foreground": "#011627",
          "powerline_symbol": "\ue0b0",
          "background": "#FEF5ED",
          "type": "time",
          "style": "powerline"
        },
        {
          "properties": {
            "cache_duration": "none",
            "style": "roundrock",
            "threshold": 0
          },
          "template": " \uf2f2 {{ .FormattedMs }} ",
          "foreground": "#D6DEEB",
          "powerline_symbol": "\ue0b0",
          "background": "#575656",
          "type": "executiontime",
          "style": "powerline"
        }
      ],
      "newline": true
    },
    {
      "type": "prompt",
      "alignment": "left",
      "segments": [
        {
          "properties": {
            "cache_duration": "none",
            "folder_icon": "\uf07b",
            "home_icon": "home",
            "style": "agnoster_full"
          },
          "template": "\u2570\u2500\ue5ff {{.Path }}\uf101",
          "foreground": "#FEF5ED",
          "type": "path",
          "style": "diamond"
        }
      ],
      "newline": true
    }
  ],
  "version": 3,
  "final_space": true
}

